MAX_KNOWLEDGE_CHARS = int(os.getenv("MAX_KNOWLEDGE_CHARS", "24000"))
MAX_ANSWER_CHARS = int(os.getenv("MAX_ANSWER_CHARS", "1600"))
OPENAI_ENABLED = os.getenv("OPENAI_ENABLED", "0").strip().lower() in {"1", "true", "yes", "on"}
