async def run_http_server() -> None:
    config = uvicorn.Config(app, host="0.0.0.0", port=PORT, log_level="info")
    server = uvicorn.Server(config)
    await server.serve()


async def main() -> None:
    await asyncio.gather(
        bot.start(DISCORD_TOKEN),
        run_http_server(),
    )


if __name__ == "__main__":
    asyncio.run(main())
